-- Tabla: qr_codes
DROP TABLE IF EXISTS `qr_codes`;
CREATE TABLE `qr_codes` (
  `id` varchar(36) NOT NULL DEFAULT uuid(),
  `tipo` enum('url','descuento','mensaje') NOT NULL,
  `titulo_interno` varchar(255) DEFAULT NULL,
  `titulo` varchar(255) DEFAULT NULL,
  `valor` text NOT NULL,
  `descuento` decimal(10,2) DEFAULT NULL,
  `tipo_descuento` enum('porcentaje','importe') DEFAULT NULL,
  `usos` int(11) DEFAULT 0,
  `max_usos` int(11) DEFAULT NULL,
  `activo` tinyint(1) DEFAULT 1,
  `created_by` varchar(36) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `expires_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `created_by` (`created_by`),
  CONSTRAINT `1` FOREIGN KEY (`created_by`) REFERENCES `usuarios` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

